export default function Hero() {
    return (
        <div className="container-fluid">
            <div className="card border-0">
                <div className="card-header d-flex border-bottom-0 bg-transparent p-5">
                    <img src={heroImage} alt="gambar hero" id="hero-image"/>
                    <p>
                        lorem
                    </p>
                </div>
            </div>
        </div>
    )
}
